import { useState, useEffect } from 'react';

const FALLBACK_VERSION = '8.1.0';
const FALLBACK_BASE = `https://github.com/sgallup23/AuraAlphaElectron/releases/download/v${FALLBACK_VERSION}`;

const FALLBACK_DATA = {
  version: FALLBACK_VERSION,
  download_urls: {
    windows: `${FALLBACK_BASE}/Aura.Alpha.Setup.${FALLBACK_VERSION}.exe`,
    macos: `${FALLBACK_BASE}/AuraAlpha_${FALLBACK_VERSION}_aarch64.dmg`,
    linux: `${FALLBACK_BASE}/AuraAlpha_${FALLBACK_VERSION}_amd64.deb`,
  },
  release_url: `https://github.com/sgallup23/AuraAlphaElectron/releases/tag/v${FALLBACK_VERSION}`,
};

// Module-scope cache so multiple components don't refetch
let _cache = null;
let _promise = null;

async function fetchWithTimeout(url, ms = 8000) {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), ms);
  try {
    const res = await fetch(url, { signal: controller.signal });
    clearTimeout(id);
    return res;
  } catch (err) {
    clearTimeout(id);
    throw err;
  }
}

async function fetchLatestVersion() {
  // Try up to 2 times with 8s timeout each
  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const res = await fetchWithTimeout('https://auraalpha.cc/api/desktop/latest-version');
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      _cache = {
        version: data.version || FALLBACK_VERSION,
        asset_version: data.asset_version || data.version || FALLBACK_VERSION,
        download_urls: data.download_urls || FALLBACK_DATA.download_urls,
        release_url: data.release_url || FALLBACK_DATA.release_url,
        loading: false,
        error: false,
      };
      return _cache;
    } catch {
      if (attempt === 1) break; // Last attempt failed
    }
  }
  // All retries exhausted — use fallback
  _cache = { ...FALLBACK_DATA, asset_version: FALLBACK_VERSION, loading: false, error: true };
  return _cache;
}

export function useLatestDesktopVersion() {
  const [state, setState] = useState(
    _cache || { ...FALLBACK_DATA, loading: true, error: false }
  );

  useEffect(() => {
    if (_cache) {
      setState(_cache);
      return;
    }
    if (!_promise) {
      _promise = fetchLatestVersion();
    }
    let cancelled = false;
    _promise.then((result) => {
      if (!cancelled) setState(result);
    });
    return () => { cancelled = true; };
  }, []);

  return state;
}
